static SCALAR_CONST_NAME_INDEX: OnceLock<HashMap<&'static str, usize>> = OnceLock::new();
static SCALAR_CONST_VALUE_INDEX: OnceLock<HashMap<ScalarCoreConst, usize>> = OnceLock::new();

#[inline]
pub fn get_const_name_index() -> &'static HashMap<&'static str, usize> {
    SCALAR_CONST_NAME_INDEX.get_or_init(|| {
        let mut index = HashMap::with_capacity(SCALAR_CONST_REGISTRY_LEN);
        for (idx, entry) in SCALAR_CONST_REGISTRY.iter().enumerate() {
            index.insert(entry.name, idx);
        }
        index
    })
}

#[inline]
pub fn get_const_value_index() -> &'static HashMap<ScalarCoreConst, usize> {
    SCALAR_CONST_VALUE_INDEX.get_or_init(|| {
        let mut index = HashMap::with_capacity(SCALAR_CONST_REGISTRY_LEN);
        for (idx, entry) in SCALAR_CONST_REGISTRY.iter().enumerate() {
            index.insert(entry.value, idx);
        }
        index
    })
}

#[inline]
pub fn get_const_entry_by_index(index: usize) -> Option<&'static ScalarCoreConstEntry> {
    SCALAR_CONST_REGISTRY.get(index)
}

#[inline]
pub fn get_const_value_by_index(index: usize) -> Option<&'static ScalarCoreConst> {
    get_const_entry_by_index(index).map(|entry| &entry.value)
}

#[inline]
pub fn find_const_index_by_name(name: &str) -> Option<usize> {
    get_const_name_index().get(name).copied()
}

#[inline]
pub fn get_const_entry_by_name(name: &str) -> Option<&'static ScalarCoreConstEntry> {
    find_const_index_by_name(name).and_then(get_const_entry_by_index)
}

#[inline]
pub fn get_const_value_by_name(name: &str) -> Option<&'static ScalarCoreConst> {
    get_const_entry_by_name(name).map(|entry| &entry.value)
}

#[inline]
pub fn find_const_index_by_value(value: &ScalarCoreConst) -> Option<usize> {
    get_const_value_index().get(value).copied()
}

#[inline]
pub fn contains_const_name(name: &str) -> bool {
    find_const_index_by_name(name).is_some()
}

#[inline]
pub fn contains_const_value(value: &ScalarCoreConst) -> bool {
    find_const_index_by_value(value).is_some()
}

#[inline]
pub fn find_const_entry_by_value(value: &ScalarCoreConst) -> Option<&'static ScalarCoreConstEntry> {
    find_const_index_by_value(value).and_then(get_const_entry_by_index)
}

#[inline]
pub fn find_const_name_by_value(value: &ScalarCoreConst) -> Option<&'static str> {
    find_const_entry_by_value(value).map(|entry| entry.name)
}

#[inline]
pub fn find_const_index_by_parts(
    int_balanced: &[i8; 36],
    frac_balanced_internal: &[i8; 44],
    balanced_negative: bool,
    radix_position: usize,
) -> Option<usize> {
    let candidate: ScalarCoreConst = (*int_balanced, *frac_balanced_internal, balanced_negative, radix_position);
    find_const_index_by_value(&candidate)
}
